#include <stdio.h>

int main() {
    // for dongusu
    printf("1'den 5'e kadar:\n");
    for (int i = 1; i <= 5; i++) {
        printf("Sayi: %d\n", i);
    }

    // while dongusu
    printf("\nGeri sayim:\n");
    int counter = 5;
    while (counter > 0) {
        printf("%d\n", counter);
        counter--;
    }

    // Dizi uzerinde dongu
    printf("\nMeyveler:\n");
    char* fruits[] = {"Elma", "Armut", "Muz", "Karpuz"};
    int size = sizeof(fruits) / sizeof(fruits[0]);

    for (int i = 0; i < size; i++) {
        printf("- %s\n", fruits[i]);
    }

    // do-while dongusu
    printf("\nDo-while ornegi:\n");
    int n = 0;
    do {
        printf("n = %d\n", n);
        n++;
    } while (n < 3);

    return 0;
}
